import{_ as t,o,c as a,ag as r}from"./chunks/framework.BD8VCRzL.js";const g=JSON.parse('{"title":"Trade Logging","description":"","frontmatter":{},"headers":[],"relativePath":"features/trade-logging.md","filePath":"features/trade-logging.md"}'),n={name:"features/trade-logging.md"};function i(s,e,l,d,u,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="trade-logging" tabindex="-1">Trade Logging <a class="header-anchor" href="#trade-logging" aria-label="Permalink to &quot;Trade Logging&quot;">​</a></h1><p>The trade entry box lives at the bottom of your screen. It is always there, fixed in place, so you can log a trade at any time without navigating away from your dashboard.</p><h2 id="how-to-log-a-trade" tabindex="-1">How to Log a Trade <a class="header-anchor" href="#how-to-log-a-trade" aria-label="Permalink to &quot;How to Log a Trade&quot;">​</a></h2><ol><li><strong>Type your trade description</strong> in the text box at the bottom of the screen</li><li><strong>Press Enter</strong> or click the &quot;Log Trade&quot; button</li><li><strong>The input flashes green</strong> to confirm success</li><li><strong>The box clears and refocuses</strong> automatically, ready for your next trade</li></ol><p>That is it. No forms, no dropdowns, no friction.</p><h2 id="what-to-type" tabindex="-1">What to Type <a class="header-anchor" href="#what-to-type" aria-label="Permalink to &quot;What to Type&quot;">​</a></h2><p>The system understands plain English. Describe what happened in whatever way makes sense to you.</p><h3 id="good-examples" tabindex="-1">Good Examples <a class="header-anchor" href="#good-examples" aria-label="Permalink to &quot;Good Examples&quot;">​</a></h3><blockquote><p>&quot;Longed NQ at 17500, hit target at 17600 for +$500&quot;</p></blockquote><blockquote><p>&quot;Short ES at 4825, stopped out for -$250&quot;</p></blockquote><blockquote><p>&quot;Chased the morning spike, knew it was wrong, lost $300&quot;</p></blockquote><blockquote><p>&quot;Waited all morning for the pullback, got it, nice +$600 winner&quot;</p></blockquote><blockquote><p>&quot;Scratched the trade, no harm done&quot;</p></blockquote><blockquote><p>&quot;Revenge traded after the loss, -$400, not following my plan&quot;</p></blockquote><h3 id="what-the-ai-figures-out" tabindex="-1">What the AI Figures Out <a class="header-anchor" href="#what-the-ai-figures-out" aria-label="Permalink to &quot;What the AI Figures Out&quot;">​</a></h3><p>The system reads your description and pulls out:</p><table tabindex="0"><thead><tr><th>Field</th><th>What It Means</th></tr></thead><tbody><tr><td>Direction</td><td>Long or short</td></tr><tr><td>Outcome</td><td>Win, loss, or breakeven</td></tr><tr><td>P&amp;L</td><td>Dollar amount (or approximation)</td></tr><tr><td>Discipline Score</td><td>+1, 0, or -1 based on how you describe the trade</td></tr><tr><td>Agency Score</td><td>+1, 0, or -1 based on whether you sound in control</td></tr></tbody></table><p>You do not need to include all details. The AI is smart enough to understand context.</p><div class="tip custom-block"><p class="custom-block-title">Be Honest</p><p>The system works best when you are honest in your descriptions. If you chased a trade, say so. If you waited patiently, say that too. The score is for you, not for judgment.</p></div><h2 id="understanding-the-scores" tabindex="-1">Understanding the Scores <a class="header-anchor" href="#understanding-the-scores" aria-label="Permalink to &quot;Understanding the Scores&quot;">​</a></h2><h3 id="discipline-score" tabindex="-1">Discipline Score <a class="header-anchor" href="#discipline-score" aria-label="Permalink to &quot;Discipline Score&quot;">​</a></h3><ul><li><strong>+1 (Green):</strong> You waited for your setup, followed your rules, traded your plan</li><li><strong>0 (Gray):</strong> Neutral — the trade was neither especially disciplined nor undisciplined</li><li><strong>-1 (Red):</strong> You deviated from your plan — chased, overtraded, ignored your rules</li></ul><h3 id="agency-score" tabindex="-1">Agency Score <a class="header-anchor" href="#agency-score" aria-label="Permalink to &quot;Agency Score&quot;">​</a></h3><ul><li><strong>+1 (Green):</strong> You made an intentional decision — you chose to enter, you chose to exit</li><li><strong>0 (Gray):</strong> Neutral — unclear whether the trade was intentional</li><li><strong>-1 (Red):</strong> You reacted emotionally — revenge trading, FOMO, fear, frustration</li></ul><h3 id="confidence-level" tabindex="-1">Confidence Level <a class="header-anchor" href="#confidence-level" aria-label="Permalink to &quot;Confidence Level&quot;">​</a></h3><p>Each score comes with a confidence indicator:</p><ul><li><strong>High confidence:</strong> The AI is sure about the score based on your description</li><li><strong>Medium confidence:</strong> Reasonable certainty</li><li><strong>Low confidence:</strong> Not enough information to be sure</li></ul><p>If the confidence is low, you might see &quot;insufficient signal&quot; — meaning the description was too vague for the AI to make a solid call. That is fine. Just be more descriptive next time.</p><h2 id="tips-for-better-logging" tabindex="-1">Tips for Better Logging <a class="header-anchor" href="#tips-for-better-logging" aria-label="Permalink to &quot;Tips for Better Logging&quot;">​</a></h2><ul><li><strong>Log between trades.</strong> The best time to log is after you close a trade, while the details are fresh.</li><li><strong>Be specific about intent.</strong> Say &quot;I waited for the EMA bounce&quot; rather than &quot;took a long.&quot; The more context, the better the score.</li><li><strong>Own your mistakes.</strong> &quot;Chased the move&quot; or &quot;revenge traded&quot; gives the AI useful information. It is not about judging you — it is about showing you your patterns.</li><li><strong>Describe outcomes you know.</strong> If you are not sure of the exact dollar amount, approximate: &quot;small winner,&quot; &quot;decent loss,&quot; &quot;about $200 up.&quot;</li></ul><h2 id="what-happens-after-you-submit" tabindex="-1">What Happens After You Submit <a class="header-anchor" href="#what-happens-after-you-submit" aria-label="Permalink to &quot;What Happens After You Submit&quot;">​</a></h2><ol><li>The trade is added to your session immediately (the charts update right away)</li><li>The AI processes your description and extracts the details</li><li>Your P&amp;L chart, discipline chart, and agency chart all update</li><li>After 5 trades, the Insights panel starts showing AI-generated observations</li></ol><p>The whole process takes a second or two. No page reload, no waiting.</p><h2 id="common-questions" tabindex="-1">Common Questions <a class="header-anchor" href="#common-questions" aria-label="Permalink to &quot;Common Questions&quot;">​</a></h2><p><strong>What if I make a typo?</strong> Just resubmit. The system processes each submission independently.</p><p><strong>Can I edit a trade after logging it?</strong> Not in the current version. If you made a mistake, log a correction as a new trade or contact support.</p><p><strong>What if the AI gets the score wrong?</strong> The scores are starting points, not definitive judgments. Use them as a mirror. If you disagree with a score, it is still useful information — it might tell you something about how you described the trade.</p><p><strong>How long is a &quot;session&quot;?</strong> A session lasts as long as you are actively trading. If you stop logging trades for more than 30 minutes, the next trade starts a new session.</p>',38)])])}const p=t(n,[["render",i]]);export{g as __pageData,p as default};
